Then make these changes:

## 1. Replace `/var/www/cortexbuild-ultimate/src/lib/supabase.ts`
Remove the Supabase client entirely. Replace with:
```typescript
// Token management for local API auth
const TOKEN_KEY = 'cortexbuild_token';
const USER_KEY = 'cortexbuild_user';

export function getToken(): string | null {
  return localStorage.getItem(TOKEN_KEY);
}

export function setToken(token: string): void {
  localStorage.setItem(TOKEN_KEY, token);
}

export function clearToken(): void {
  localStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(USER_KEY);
}

export function getStoredUser(): Record<string, unknown> | null {
  const raw = localStorage.getItem(USER_KEY);
  return raw ? JSON.parse(raw) : null;
}

export function setStoredUser(user: Record<string, unknown>): void {
  localStorage.setItem(USER_KEY, JSON.stringify(user));
}

export const API_BASE = '/api';
```

## 2. Replace `/var/www/cortexbuild-ultimate/src/services/api.ts`
Replace the entire file with a new implementation that calls the local Express API. The API base URL is `/api`. Use Bearer token auth from `getToken()`.

Implement these helpers:
```typescript
async function apiFetch<T>(path: string, options?: RequestInit): Promise<T> {
  const token = getToken();
  const res = await fetch(`${API_BASE}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
      ...options?.headers,
    },
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({ message: res.statusText }));
    throw new Error(err.message || 'Request failed');
  }
  return res.json();
}

async function fetchAll<T>(endpoint: string): Promise<T[]> {
  return apiFetch<T[]>(`/${endpoint}`);
}

async function insertRow<T>(endpoint: string, row: Record<string, unknown>): Promise<T> {
  return apiFetch<T>(`/${endpoint}`, { method: 'POST', body: JSON.stringify(row) });
}

async function updateRow<T>(endpoint: string, id: string, data: Record<string, unknown>): Promise<T> {
  return apiFetch<T>(`/${endpoint}/${id}`, { method: 'PUT', body: JSON.stringify(data) });
}

async function deleteRow(endpoint: string, id: string): Promise<void> {
  await apiFetch(`/${endpoint}/${id}`, { method: 'DELETE' });
}
```

